import React, { useEffect, useState } from 'react';
import { ToastContainer, toast } from 'react-toastify';
import { Link as RouterLink } from 'react-router-dom';
import { FaExternalLinkAlt, FaUserCircle, FaUsers } from 'react-icons/fa';
import { useTranslation } from 'react-i18next';
import LoadingScreen from '../../components/LoadScreen';
import api from '../../services/api';
import 'react-toastify/dist/ReactToastify.css';

import { Button } from '../../components/Form';
import Link from '../../components/Link';
import { Container, ManageTeamsContainer, TeamsContainer } from './styles';
import { CardTeam } from '../../components/Card/styles';

export default function Teams() {
  const [loading, setLoading] = useState(true);
  const [manageTeams, setManageTeams] = useState([]);
  const [teams, setTeams] = useState([]);
  const { t } = useTranslation();

  useEffect(() => {
    async function loadData() {
      const { data: manageTeamsResponse } = await api.get(
        '/v1/me/teams/creator'
      );
      const { data: teamsResponse } = await api.get('/v1/me/teams/member');

      setManageTeams(manageTeamsResponse.teams);
      setTeams(teamsResponse.teams);
      setLoading(false);
    }

    loadData();
  }, []);

  function filterManageTeam(id) {
    const newManageTeams = manageTeams.filter(team => team.id !== id);

    setManageTeams(newManageTeams);
  }

  async function handleTeamDelete(id) {
    try {
      // eslint-disable-next-line no-alert
      const action = window.confirm(t('common.confirm_delete'));

      if (action) {
        await api.delete(`/v1/teams/${id}`);

        toast(t('teams.deleted'), {
          className: 'toast-background-success',
          bodyClassName: 'toast-font-size',
          progressClassName: 'toast-progress-bar-success',
        });

        filterManageTeam(id);
      }
    } catch (error) {
      toast(
        error.response.data.fields
          ? error.response.data.fields[0].message
          : error.response.data.message,
        {
          className: 'toast-background',
          bodyClassName: 'toast-font-size',
          progressClassName: 'toast-progress-bar',
        }
      );
    }
  }

  return loading ? (
    <LoadingScreen />
  ) : (
    <Container>
      <h1 style={{ textAlign: 'center' }}>{t('teams.title')}</h1>
      <h2 className="heading_section">{t('teams.manage_section')}</h2>

      <ManageTeamsContainer>
        {manageTeams.length > 0 ? (
          manageTeams.map(team => (
            <div className="box">
              <CardTeam key={team.id}>
                <div className="team-id">
                  <p>{String(team.id).padStart(3, '0')}</p>
                </div>

                <div className="team-content">
                  <p className="title">
                    {t('teams.team_of')}{' '}
                    <RouterLink
                      to={`/app/hackathon/${team.hackathon.id}`}
                      className="link link--black"
                    >
                      {team.hackathon.title}
                    </RouterLink>
                  </p>

                  <div className="container">
                    <div className="creator">
                      {t('common.created_by')}{' '}
                      <RouterLink
                        target="_blank"
                        to={`/${team.creator.nickname}`}
                        className="link"
                      >
                        {team.creator.name}
                      </RouterLink>
                    </div>

                    <div className="members">
                      <FaUsers />
                      <strong>{t('common.members')}</strong>
                    </div>

                    <div className="member">
                      {team.members.length > 0
                        ? ''
                        : t('common.no_members')}
                      {team.members.map(member => (
                        <RouterLink
                          target="_blank"
                          to={`/${member.nickname}`}
                          className="member__link"
                        >
                          <FaUserCircle className="link" size={25} />{' '}
                          {member.member.name}{' '}
                          <FaExternalLinkAlt class="external" size={15} />
                        </RouterLink>
                      ))}
                    </div>
                  </div>

                  <div className="actions">
                    <Link
                      to={`/app/hackathon/team/${team.id}/manage`}
                      text={t('common.edit')}
                      style={{ marginLeft: '15px' }}
                    />
                    <Button
                      text={t('common.delete')}
                      color="#e3133e"
                      style={{ marginLeft: '15px' }}
                      onClick={() => handleTeamDelete(team.id)}
                    />
                  </div>
                </div>
              </CardTeam>
            </div>
          ))
        ) : (
          <h3>{t('teams.no_manage_teams')}</h3>
        )}
      </ManageTeamsContainer>

      <h2 className="heading_section">{t('teams.participate_section')}</h2>
      <TeamsContainer>
        {teams.length > 0 ? (
          teams.map(team => (
            <div className="box">
              <CardTeam key={team.team_id}>
                <div className="team-id">
                  <p>{String(team.team_id).padStart(3, '0')}</p>
                </div>

                <div className="team-content">
                  <p className="title">
                    {t('teams.team_of')}{' '}
                    <strong>{team.team.hackathon.title}</strong>
                  </p>

                  <div className="container">
                    <div className="creator">
                      {t('common.created_by')}{' '}
                      <RouterLink
                        target="_blank"
                        to={`/${team.team.creator.nickname}`}
                        className="link"
                      >
                        {team.team.creator.name}
                      </RouterLink>
                    </div>

                    <div className="members">
                      <FaUsers />
                      <strong>{t('common.members')}</strong>
                    </div>

                    <div className="member">
                      {team.team.members.length > 0
                        ? ''
                        : t('common.no_members')}
                      {team.team.members.map(member => (
                        <RouterLink
                          target="_blank"
                          to={`/${member.nickname}`}
                          className="member__link"
                        >
                          <FaUserCircle className="link" size={25} />{' '}
                          {member.name}{' '}
                          <FaExternalLinkAlt class="external" size={15} />
                        </RouterLink>
                      ))}
                    </div>
                  </div>

                  <div className="actions">
                    <Link
                      to={`/app/hackathon/${team.team.hackathon.id}`}
                      text={t('teams.go_to_event')}
                    />
                  </div>
                </div>
              </CardTeam>
            </div>
          ))
        ) : (
          <h3>{t('teams.no_teams')}</h3>
        )}
      </TeamsContainer>

      <ToastContainer />
    </Container>
  );
}
